      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  const projectId = req.params.projectId;
  try {
    const tasks = await tasksService.getTasksByProject(projectId);
    if (!tasks) {
      return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
    }
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.get('/?status=done', async (req, res) => {
  const projectId = req.params.projectId;
  try {
    const tasks = await tasksService.getTasksByProject(projectId);
    if (!tasks) {
      return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
    }
    const doneTasks = tasks.filter(task => task.status === 'done');
    res.json({ tasks: doneTasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  const projectId = req.params.projectId;
  const { title } = req.body;
  if (!title) {
    return sendError(res, 400, 'INVALID_INPUT', 'Title is required');
  }
  try {
    const task = await tasksService.createTask(projectId, title);
    if (!task) {
      return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
    }
    res.status(201).json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;
"
