    {
      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('../../lib/id');

let tasksStore = [];

const getTasksByProject = (projectId) => {
  return Promise.resolve(tasksStore.filter(task => task.projectId === projectId));
};

const createTask = (projectId, title) => {
  const newTask = { id: randomUUID(), projectId, title, status: 'todo' };
  tasksStore.push(newTask);
  return Promise.resolve(newTask);
};

module.exports = { getTasksByProject, createTask };
