    {
      "path": "src/modules/comments/service.js",
      "content": "const { randomUUID } = require('../../lib/id');

let commentsStore = [];

const getCommentsByTask = (projectId, taskId) => {
  return Promise.resolve(commentsStore.filter(comment => comment.projectId === projectId && comment.taskId === taskId));
};

const addCommentToTask = (projectId, taskId, content) => {
  const newComment = { id: randomUUID(), projectId, taskId, content };
  commentsStore.push(newComment);
  return Promise.resolve(newComment);
};

module.exports = { getCommentsByTask, addCommentToTask };
